{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke test가 통과할 경우 금요일 15:00 KST로 한다.",
        "conditions": ["smoke test 통과"]
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다.",
        "conditions": ["contract 자체가 잘못된 경우에만 script 검토"]
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "status": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "internal_stretch_goal_only",
        "note": "최종 공개 릴리스 결정이 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README install steps를 목요일까지 검토",
        "reason": "가능하면 검토한다는 언급은 있었으나 담당자가 지정되지 않음"
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부",
        "reason": "결정되지 않음"
      },
      {
        "item": "최종 릴리스 승인 권한자",
        "reason": "결정되지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README install steps가 오래된 경우 release notes가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_action_from_fixture"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed_action_from_fixture"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke results를 게시한 후 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed_without_exact_deadline",
      "source_certainty": "confirmed_action_from_fixture"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "unassigned_non_decision",
      "source_certainty": "mentioned_but_no_owner_assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 smoke test 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "Doyun의 action_items.md failure triage note가 금요일 12:00 KST까지 작성되었는지 확인한다.",
      "smoke 결과 게시 후 Hara가 generated tarball path를 확인했는지 확인한다.",
      "README install steps 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "운영 환경 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "fixture에 명시된 사실만 사용한다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 마감일 정보는 명시되지 않았으면 생성하지 않는다.",
    "수요일 릴리스는 공개 릴리스 결정이 아니라 내부 stretch goal로만 기록한다.",
    "packageName mismatch 무시 제안은 거절된 제안으로만 기록한다.",
    "조건부 결정은 조건을 함께 기록한다."
  ]
}
